{"files": [{"path": "README.md", "content": "# Simple TODO API

This is a simple REST API for managing TODOs, implemented using Node.js with no external dependencies.

## Endpoints

- **GET /health** - Returns server health status.
- **GET /openapi.json** - Returns the OpenAPI specification.
- **GET /todos** - Lists all todos.
- **POST /todos** - Creates a new todo (requires `title` in JSON body).
- **GET /todos/:id** - Retrieves a specific todo by ID.
- **PATCH /todos/:id** - Updates a specific todo (set `done` to true).
- **DELETE /todos/:id** - Deletes a specific todo.

## Usage

To run the server, use:
```sh
npm start
```

This will start the server on port 3000. You can interact with the API using tools like `curl` or Postman.
"}, {"path": "package.json", "content": "{
  "name": "todo-api",
  "version": "1.0.0",
  "description": "A simple TODO API implemented in Node.js without external dependencies.",
  "main": "src/server.js",
  "type": "commonjs",
  "scripts": {
    "start": "node src/server.js"
  }
}
"}, {"path": "openapi.json", "content": "{
  "openapi": "3.0.1",
  "info": {
    "title": "TODO API",
    "version": "1.0.0"
  },
  "paths": {},
  "components": {}
}"}, {"path": "src/server.js", "content": "const http = require('node:http');
const url = require('node:url');
const crypto = require('node:crypto');
const fs = require('node:fs');
const path = require('node:path');

function createServer({ dataPath }) {
  const todos = [];

  function loadTodos() {
    if (fs.existsSync(dataPath)) {
      const fileData = fs.readFileSync(dataPath, 'utf8');
      return JSON.parse(fileData).todos || [];
    }
    return todos;
  }

  function saveTodos() {
    fs.writeFileSync(dataPath, JSON.stringify({ todos: todos }, null, 2));
  }

  const server = http.createServer((req, res) => {
    const parsedUrl = url.parse(req.url, true);
    if (parsedUrl.pathname === '/health') {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ok: true }));
    } else if (parsedUrl.pathname === '/openapi.json') {
      const openApiSpec = require('./openapi.json');
      openApiSpec.paths['/todos'] = { get: {}, post: {} };
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify(openApiSpec));
    } else if (parsedUrl.pathname === '/todos') {
      if (req.method === 'GET') {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true, todos: loadTodos() }));
      } else if (req.method === 'POST') {
        let body = '';
        req.on('data', chunk => { body += chunk.toString(); });
        req.on('end', () => {
          const newTodo = JSON.parse(body);
          if (!newTodo.title) {
            res.writeHead(400, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: false, error: 'Title is required' }));
          } else {
            const todo = { id: crypto.randomUUID(), ...newTodo, createdAt: new Date().toISOString() };
            todos.push(todo);
            saveTodos();
            res.writeHead(201, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: true, todo }));
          }
        });
      } else {
        res.writeHead(405, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: false, error: 'Method Not Allowed' }));
      }
    } else if (parsedUrl.pathname.startsWith('/todos/')) {
      const id = parsedUrl.pathname.split('/').pop();
      if (req.method === 'GET') {
        const todo = todos.find(t => t.id === id);
        if (todo) {
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true, todo }));
        } else {
          res.writeHead(404, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, error: 'Todo not found' }));
        }
      } else if (req.method === 'PATCH') {
        let body = '';
        req.on('data', chunk => { body += chunk.toString(); });
        req.on('end', () => {
          const updates = JSON.parse(body);
          const index = todos.findIndex(t => t.id === id);
          if (index !== -1) {
            const todo = { ...todos[index], ...updates, doneAt: updates.done ? new Date().toISOString() : undefined };
            todos[index] = todo;
            saveTodos();
            res.writeHead(200, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: true, todo }));
          } else {
            res.writeHead(404, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: false, error: 'Todo not found' }));
          }
        });
      } else if (req.method === 'DELETE') {
        const index = todos.findIndex(t => t.id === id);
        if (index !== -1) {
          todos.splice(index, 1);
          saveTodos();
          res.writeHead(204, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true }));
        } else {
          res.writeHead(404, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, error: 'Todo not found' }));
        }
      }
    } else {
      res.writeHead(404, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ok: false, error: 'Not Found' }));
    }
  });

  return server;
}

module.exports = createServer;"}]}
